def update_scripts():
    """모든 에피소드 스크립트의 narration 업데이트"""
    for prefix, narrations in NARRATIONS.items():
        script_path = SCRIPTS_DIR / f"{prefix}_script.json"
        if not script_path.exists():
            print(f"[SKIP] {script_path}")
            continue

        with open(script_path, "r", encoding="utf-8") as f:
            scenes = json.load(f)

        if len(narrations) != len(scenes):
            print(f"[ERROR] {prefix}: {len(narrations)} narrations != {len(scenes)} scenes")
            continue

        for i, scene in enumerate(scenes):
            old = scene["narration"]
            scene["narration"] = narrations[i]
            old_len = len(old)
            new_len = len(narrations[i])
            diff = new_len - old_len
            sign = "+" if diff > 0 else ""
            print(f"  {scene['id']}: {old_len}→{new_len} ({sign}{diff}자)")

        with open(script_path, "w", encoding="utf-8") as f:
            json.dump(scenes, f, ensure_ascii=False, indent=2)

        print(f"[OK] {prefix} updated\n")


if __name__ == "__main__":
    update_scripts()
